SELECT COUNT(*) AS active_pio_peripherals
FROM peripherals
WHERE status = 'active' AND pio_support = 'yes';

SELECT peripheral_name
FROM peripherals
WHERE status = 'active';

SELECT COUNT(*) AS error_count
FROM peripheral_logs
WHERE peripheral_id = 0 AND log_type = 'error';

SELECT type_name
FROM peripheral_types
WHERE power_consumption < '50 mW';

SELECT COUNT(report_id) AS report_count
FROM peripheral_reports
WHERE peripheral_id = 0;

SELECT peripheral_name 
FROM peripherals 
ORDER BY peripheral_name;

SELECT log_date, log_message
FROM peripheral_logs
WHERE log_severity = 'error';
